UserObject.mermaidData:
{
  "data": "
classDiagram

%% ─────────────────────────────────────────
%% CAPA 1 — DOMINIO
%% ─────────────────────────────────────────

class User {
    <<Aggregate Root>>
    +id : UserId
    +email : Email
    +password : Password
    +username : Username
}

class UserId {
    <<Value Object>>
    +value : string
}

class Email {
    <<Value Object>>
    +value : string
}

class Password {
    <<Value Object>>
    +hash : string
}

class Username {
    <<Value Object>>
    +value : string
}

class Level {
    <<Aggregate Root>>
    +id : LevelId
    +board : Board
    +rules : LevelRules
    +order : LevelOrder
    +isScorePlausible(score Score) bool
}

class LevelId {
    <<Value Object>>
    +value : string
}

class Board {
    <<Value Object>>
    +nodes : List~CellNode~
    +edges : List~Edge~
}

class CellNode {
    <<Value Object>>
    +id : NodeId
    +position : Position
    +type : CellType
}

class NodeId {
    <<Value Object>>
    +value : string
}

class Edge {
    <<Value Object>>
    +from : NodeId
    +to : NodeId
}

class LevelRules {
    <<Value Object>>
    +timeLimit : int
    +maxMoves : int
    +maxPossibleScore : int
    +difficulty : string
}

class LevelOrder {
    <<Value Object>>
    +value : int
}

class Position {
    <<Interface>>
}

class GridPosition {
    <<Value Object>>
    +row : int
    +column : int
}

class CellType {
    <<Interface>>
}

class ArrowCell {
    <<Entity>>
    +direction : Direction
    +rotate() void
}

class WallCell {
    <<Entity>>
}

class EmptyCell {
    <<Entity>>
}

class ExitCell {
    <<Entity>>
}

class Direction {
    <<Value Object>>
    +value : string
    +next() Direction
}

class Progress {
    <<Aggregate Root>>
    +userId : UserId
    +levelId : LevelId
    +completed : boolean
    +bestScore : Score
    +registerAttempt(score Score) void
}

class Score {
    <<Value Object>>
    +value : int
}

class CellFactory {
    <<Domain Factory>>
    +create(rawData object) CellType
}

%% ─────────────────────────────────────────
%% CAPA 2 — CASOS DE USO
%% ─────────────────────────────────────────

class IUserRepository {
    <<Port>>
    +findById(id UserId) User
    +findByEmail(email Email) User
    +save(user User) void
}

class ILevelRepository {
    <<Port>>
    +findById(id LevelId) Level
    +findAll() List~Level~
    +save(level Level) void
}

class IProgressRepository {
    <<Port>>
    +findByUserAndLevel(userId UserId, levelId LevelId) Progress
    +findTopScoresByLevel(levelId LevelId, limit int) List~Progress~
    +save(progress Progress) void
}

class RegisterUserUseCase {
    <<Use Case>>
    +execute(email string, password string, username string) UserDTO
}

class LoginUseCase {
    <<Use Case>>
    +execute(email string, password string) TokenDTO
}

class GetLevelsUseCase {
    <<Use Case>>
    +execute() List~LevelDTO~
}

class SyncProgressUseCase {
    <<Use Case>>
    +execute(userId string, levelId string, score int) void
}

class GetLeaderboardUseCase {
    <<Use Case>>
    +execute(levelId string, limit int) List~LeaderboardEntryDTO~
}

%% ─────────────────────────────────────────
%% CAPA 3 — ADAPTADORES DE INTERFAZ
%% ─────────────────────────────────────────

class AuthController {
    <<Controller>>
    +register(body RegisterDTO) UserDTO
    +login(body LoginDTO) TokenDTO
}

class LevelController {
    <<Controller>>
    +getAll() List~LevelDTO~
}

class ProgressController {
    <<Controller>>
    +sync(body SyncDTO) void
}

class LeaderboardController {
    <<Controller>>
    +getLeaderboard(levelId string, limit int) List~LeaderboardEntryDTO~
}

class TypeOrmUserRepository {
    <<Repository>>
    +findById(id UserId) User
    +findByEmail(email Email) User
    +save(user User) void
}

class TypeOrmLevelRepository {
    <<Repository>>
    +findById(id LevelId) Level
    +findAll() List~Level~
    +save(level Level) void
}

class TypeOrmProgressRepository {
    <<Repository>>
    +findByUserAndLevel(userId UserId, levelId LevelId) Progress
    +findTopScoresByLevel(levelId LevelId, limit int) List~Progress~
    +save(progress Progress) void
}

class UserEntity {
    <<ORM Entity>>
    +id : string
    +email : string
    +passwordHash : string
    +username : string
}

class LevelEntity {
    <<ORM Entity>>
    +id : string
    +boardData : jsonb
    +timeLimit : int
    +maxMoves : int
    +maxPossibleScore : int
    +difficulty : string
    +order : int
}

class ProgressEntity {
    <<ORM Entity>>
    +userId : string
    +levelId : string
    +completed : boolean
    +bestScore : int
}

class UserMapper {
    <<Mapper>>
    +toDomain(entity UserEntity) User
    +toEntity(user User) UserEntity
}

class LevelMapper {
    <<Mapper>>
    +toDomain(entity LevelEntity) Level
    +toEntity(level Level) LevelEntity
}

class ProgressMapper {
    <<Mapper>>
    +toDomain(entity ProgressEntity) Progress
    +toEntity(progress Progress) ProgressEntity
}

%% ─────────────────────────────────────────
%% CAPA 4 — FRAMEWORKS E INFRAESTRUCTURA
%% ─────────────────────────────────────────

class JwtAuthGuard {
    <<AOP — Seguridad>>
    +canActivate(context ExecutionContext) boolean
}

class LoggingInterceptor {
    <<AOP — Logging>>
    +intercept(context ExecutionContext, next CallHandler) Observable
}

class JwtStrategy {
    <<Infrastructure>>
    +validate(payload JwtPayload) User
}",
  "config": null
}

{
  "data": "classDiagram
class IUseCase {
    <<Interface>>
    +execute(command TCommand) void
}

class SyncProgressCommand {
    <<Command>>
    +userId : string
    +levelId : string
    +score : int
}

class RegisterUserCommand {
    <<Command>>
    +email : string
    +password : string
    +username : string
}

class LoginCommand {
    <<Command>>
    +email : string
    +password : string
}

class GetLevelsCommand {
    <<Command>>
}

class GetLeaderboardCommand {
    <<Command>>
    +levelId : string
    +limit : int
}

%% ─────────────────────────────────────────
%% CAPA 3 — ADAPTADORES DE INTERFAZ
%% Agregar estas clases nuevas
%% ─────────────────────────────────────────

class LoggingUseCaseDecorator {
    <<AOP — Logging>>
    -decoratee : IUseCase~TCommand~
    +execute(command TCommand) void
}

class SecureUseCaseDecorator {
    <<AOP — Seguridad>>
    -decoratee : IUseCase~TCommand~
    +execute(command TCommand) void
}",
  "config": null
}
